from dataclasses import dataclass

@dataclass
class ClientRecord:
    client_id: str
    document_id: str

    @classmethod
    def from_dict(cls, d: dict) -> 'ClientRecord':
        cid = str(d.get('client_id', '')).strip()
        doc = str(d.get('document_id', '')).strip()
        if not cid or not doc:
            raise ValueError('client_id/document_id vacíos')
        return cls(cid, doc)

print(ClientRecord.from_dict({'client_id': 'C1', 'document_id': 'DNI-1'}))
try:
    ClientRecord.from_dict({'client_id': '', 'document_id': 'x'})
except ValueError as e:
    print(e)

