class Service:
    def __init__(self, repo):
        self.repo = repo
    def register(self, id, name):
        self.repo.save({'id': id, 'name': name})
        return self.repo.get(id)

svc = Service(FakeRepo())
assert svc.register('C1', 'Ana')['name'] == 'Ana'
